    const bool safetyAfter = tm.isThreadSafetyEnabled();

    return ThreadSafetyStatus{
        .safetyBefore = safetyBefore,
        .safetyAfter = safetyAfter,
        .threadCountBefore = countBefore,
        .threadCountAfter = countAfter,
